class Solution:
    def maxOperations(self, nums):
        from functools import lru_cache
        n = len(nums)
        def solve(target):
            @lru_cache(maxsize=None)
            def dp(lo, hi):
                if hi - lo < 1:
                    return 0
                best = 0
                if nums[lo] + nums[lo+1] == target:
                    best = max(best, 1 + dp(lo+2, hi))
                if nums[hi-1] + nums[hi] == target:
                    best = max(best, 1 + dp(lo, hi-2))
                if nums[lo] + nums[hi] == target:
                    best = max(best, 1 + dp(lo+1, hi-1))
                return best
            r = dp(0, n-1)
            dp.cache_clear()
            return r
        candidates = [nums[0]+nums[1], nums[-1]+nums[-2], nums[0]+nums[-1]]
        return max(solve(t) for t in set(candidates))

