var maxOperations = function(nums) {
    const n = nums.length;
    function solve(target) {
        const memo = new Map();
        function dp(lo, hi) {
            if (hi - lo < 1) return 0;
            const key = lo * 2001 + hi;
            if (memo.has(key)) return memo.get(key);
            let best = 0;
            if (nums[lo]+nums[lo+1] === target) best = Math.max(best, 1+dp(lo+2,hi));
            if (nums[hi-1]+nums[hi] === target) best = Math.max(best, 1+dp(lo,hi-2));
            if (nums[lo]+nums[hi] === target) best = Math.max(best, 1+dp(lo+1,hi-1));
            memo.set(key, best);
            return best;
        }
        return dp(0, n-1);
    }
    const cands = new Set([nums[0]+nums[1], nums[n-1]+nums[n-2], nums[0]+nums[n-1]]);
    return Math.max(...[...cands].map(solve));
};
